@startuml
skinparam UMLClassDiagram font "Comic Sans MS"

class Joint {
    label "E" as label1
    label "Joint" as label2
    link label1..>label2
}

class Head {
    label "Head"
}

class Neck {
    label "Neck"
}

class Shoulder {
    label "Shoulder"
}

class Hip {
    label "Hip"
}

class Knee {
    label "Knee"
}

class Foot {
    label "Foot"
}

Joint -- Head
Joint -- Neck
Joint -- Shoulder
Joint -- Hip
Joint -- Knee
Joint -- Foot

@enduml
